Here's an example of how you can use HomeyScript to control an Edimax air quality sensor:

```
// Require the HTTP app module
const http = Homey.apps.apps.http;

// Set your Edimax password here
const PASSWORD = "your_edimax_password";

// Define the endpoint for reading the sensor data
const ENDPOINT = "http://edimax.local/cgi-bin/cgi_edimax?cmd=get&token=%s&ck=%d";

// Define a function to rotate bytes to the left
function rotateByte(byte, rotations) {
  return (byte << rotations | byte >> (8 - rotations)) & 0xFF;
}

// Define a function to rotate the JSON response
function rotateJson(response) {
  const rotations = response.charCodeAt(0) - '{'.charCodeAt(0);
  return '{' + Array.from(response.slice(1), byte => String.fromCharCode(rotateByte(byte.charCodeAt(0), rotations))).join('');
}

// Define a function to get sensor readings
async function getSensorReadings() {
  // Generate a token for this request
  const token = Date.now();

  // Prepare the request parameters
  const params = {
    url: ENDPOINT.replace("%s", PASSWORD).replace("%d", token),
    method: "GET",
    headers: {
      "Content-Type": "application/json",
      "X-Requested-With": "XMLHttpRequest"
    },
    body: {}
  };

  // Send the request and get the response
  let response = await http.fetch(params);

  // Rotate the response bytes to plain JSON
  response = rotateJson(response.body);

  // Parse the JSON response
  const data = JSON.parse(response)["status"];

  // Return the sensor readings
  return {
    temperature: parseFloat(data["temperature"]),
    humidity: parseFloat(data["moisture"]),
    pm25: parseInt(data["pm2.5"]),
    pm10: parseInt(data["pm10"]),
    co2: parseInt(data["co2"]),
    hcho: parseInt(data["hcho"]),
    tvoc: parseInt(data["tvoc"])
  };
}

// Define a flow action to get sensor readings
Homey.flow.getAction("get_sensor_readings").registerRunListener(async(args, state) => {
  try {
    const readings = await getSensorReadings();
    return Promise.resolve(readings);
  } catch (error) {
    return Promise.reject(error.message);
  }
});
```

You can then create a flow that uses the "get_sensor_readings" action to get the sensor readings and use them to trigger other actions, such as turning on a smart plug if the CO2 level is too high.

